  ('pukao-64311456-moex-00077', 'pukao-64311456', 'pukao-64311456-moex-114-d1a761c9', 'sub-pukao-64311456-03', NULL, 'single_choice', '關於撤銷違法行政處分之敘述，下列何者正確？', '["應由原處分機關報請上級機關核准後方得撤銷", "若處分之受益人無信賴不值得保護之情形，且其信賴利益顯然大於撤銷所欲維護之公益者，不得撤銷", "處分經撤銷後原則上自撤銷時起失其效力", "授予利益之違法行政處分經撤銷後，受益人得向為撤銷之機關請求國家賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:33+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "405", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL)
